package cmd

import (
	"fmt"
	"net"
	"os"
	"os/exec"
	"strconv"
	"strings"
	"time"

	"github.com/sandcastle/cli/api"
	"github.com/sandcastle/cli/internal/config"
	"github.com/spf13/cobra"
)

var connectMosh bool

func init() {
	rootCmd.AddCommand(connectCmd)
	rootCmd.AddCommand(sshCmd)
