   141→		if err == nil {
   142→			conn.Close()
   143→			if printed {
   144→				fmt.Println()
   145→			}
   146→			if os.Getenv("VERBOSE") == "1" {
   147→				fmt.Fprintf(os.Stderr, "\033[2m[verbose] SSH connection successful!\033[0m\n")
   148→			}
   149→			return nil
   150→		}
   151→		if !printed {
   152→			fmt.Printf("Waiting for SSH to be ready...")
   153→			printed = true
   154→		}
   155→		fmt.Print(".")
   156→		time.Sleep(500 * time.Millisecond)
   157→	}
   158→
   159→	fmt.Println()
   160→	return fmt.Errorf("timeout waiting for SSH at %s", addr)
   161→}
