   163→func sshExec(host string, port int, user string, remoteCmd string, extraArgs string) error {
   164→	sshArgs := []string{
   165→		"-p", strconv.Itoa(port),
   166→		"-o", "StrictHostKeyChecking=no",
   167→		"-o", "UserKnownHostsFile=/dev/null",
   168→		"-o", "LogLevel=ERROR",
   169→	}
   170→	if extraArgs != "" {
   171→		sshArgs = append(sshArgs, strings.Fields(extraArgs)...)
   172→	}
   173→	sshArgs = append(sshArgs, fmt.Sprintf("%s@%s", user, host))
   174→	if remoteCmd != "" {
   175→		sshArgs = append(sshArgs, "-t", remoteCmd)
   176→	}
   177→
   178→	sshPath, err := exec.LookPath("ssh")
   179→	if err != nil {
   180→		return fmt.Errorf("ssh not found: %w", err)
   181→	}
   182→
   183→	if os.Getenv("VERBOSE") == "1" {
   184→		fmt.Fprintf(os.Stderr, "→ ssh %s\n", shellJoin(sshArgs))
   185→	}
   186→
   187→	proc := &os.ProcAttr{
   188→		Files: []*os.File{os.Stdin, os.Stdout, os.Stderr},
   189→	}
   190→	process, err := os.StartProcess(sshPath, append([]string{"ssh"}, sshArgs...), proc)
   191→	if err != nil {
   192→		return fmt.Errorf("starting ssh: %w", err)
   193→	}
   194→
   195→	state, err := process.Wait()
   196→	if err != nil {
   197→		return err
   198→	}
   199→	if !state.Success() {
   200→		os.Exit(state.ExitCode())
   201→	}
   202→	return nil
   203→}
   204→
   205→func moshExec(host string, port int, user string, remoteCmd string, extraArgs string) error {
   206→	sshOpts := fmt.Sprintf("ssh -p %d -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null -o LogLevel=ERROR", port)
   207→	if extraArgs != "" {
   208→		sshOpts += " " + extraArgs
   209→	}
   210→
   211→	moshArgs := []string{
   212→		"--ssh=" + sshOpts,
   213→		fmt.Sprintf("%s@%s", user, host),
   214→	}
   215→	if remoteCmd != "" {
   216→		moshArgs = append(moshArgs, "--")
   217→		moshArgs = append(moshArgs, strings.Fields(remoteCmd)...)
   218→	}
   219→
   220→	moshPath, err := exec.LookPath("mosh")
   221→	if err != nil {
   222→		return fmt.Errorf("mosh not found in PATH — install mosh on your local machine first (https://mosh.org): %w", err)
   223→	}
   224→
   225→	if os.Getenv("VERBOSE") == "1" {
   226→		fmt.Fprintf(os.Stderr, "→ mosh %s\n", shellJoin(moshArgs))
   227→	}
   228→
   229→	proc := &os.ProcAttr{
   230→		Files: []*os.File{os.Stdin, os.Stdout, os.Stderr},
   231→	}
   232→	process, err := os.StartProcess(moshPath, append([]string{"mosh"}, moshArgs...), proc)
   233→	if err != nil {
   234→		return fmt.Errorf("starting mosh: %w", err)
   235→	}
   236→
   237→	state, err := process.Wait()
   238→	if err != nil {
   239→		return err
   240→	}
   241→	if !state.Success() {
   242→		os.Exit(state.ExitCode())
   243→	}
   244→	return nil
   245→}
   246→
   247→func shellJoin(args []string) string {
   248→	quoted := make([]string, len(args))
   249→	for i, a := range args {
   250→		if strings.ContainsAny(a, " \t\n\"'\\") {
   251→			quoted[i] = fmt.Sprintf("%q", a)
   252→		} else {
   253→			quoted[i] = a
   254→		}
   255→	}
   256→	return strings.Join(quoted, " ")
   257→}
